Paste the following code into the `Program.cs` file.

```csharp
using MongoDB.Bson;
using MongoDB.Driver;
using System;
using System.Threading.Tasks;

namespace MongoDBAtlasSearch
{
    class Program
    {
        static async Task Main(string[] args)
        {
            // Replace with your MongoDB connection string
            string connectionString = "mongodb+srv://<username>:<password>@<cluster-url>/sample_mflix";
            var client = new MongoClient(connectionString);
            var database = client.GetDatabase("<databaseName>");

            // Create a MongoDB Search index on the objectId field
            var indexDefinition = new BsonDocument
            {
                { "createSearchIndexes", "<collectionName>" },
                { "indexes", new BsonArray
                    {
                        new BsonDocument
                        {
                            { "name", "<indexName>" },
                            { "definition", new BsonDocument
                                {
                                    { "mappings", new BsonDocument
                                        {
                                            { "dynamic", true | false },
                                            { "fields", new BsonDocument
                                                {
                                                    { "<fieldName>", new BsonDocument
                                                        {
                                                            { "type", "objectId" }
                                                        }
                                                    }
                                                }
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
            };

            var result = await database.RunCommandAsync<BsonDocument>(indexDefinition);
            Console.WriteLine($"Index creation result: {result.ToJson()}");
        }
    }
}

```

Replace `<connection-string>` with the connection string for your
Atlas cluster or local Atlas deployment.

Atlas Cluster

Your connection string should use the following format:

```
mongodb+srv://<db_username>:<db_password>@<clusterName>.<hostname>.mongodb.net
```

To learn more, see [Driver](connect-via-driver).

Local or Self-Managed

Your connection string should use the
following format:

```
mongodb://localhost:<port-number>/?directConnection=true
```

To learn more, see [Connection Strings](manual/reference/connection-string).

